import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XssSecureServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("userInput");

        // Sanitize user input using OWASP ESAPI or a similar library
        String sanitizedInput = encodeForHTML(userInput);

        // Properly handle user input with encoding
        String output = "Hello, " + sanitizedInput;

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();
        out.println(output);
    }

    private String encodeForHTML(String input) {
        // Implement proper encoding to prevent XSS attacks
        return input.replace("&", "&amp;")
                    .replace("<", "&lt;")
                    .replace(">", "&gt;")
                    .replace("\"", "&quot;")
                    .replace("'", "&#x27;")

